// Generated by Claude Opus 4.6

import {
  Alert,
  Button,
  Card,
  CardBody,
  EmptyState,
  EmptyStateActions,
  EmptyStateBody,
  EmptyStateFooter,
  EmptyStateVariant,
  Flex,
  FlexItem,
  Tooltip,
} from '@patternfly/react-core';
import React from 'react';

import AgentPodEvents from '@/components/AgentPodEvents';
import AgentTerminal from '@/components/AgentTerminal';
import TerminalTools from '@/components/TerminalTools';
import styles from '@/pages/DevfileDetails/AgentPanel/index.module.css';
import { AgentPodPhase, AgentPodStatus } from '@/store/LocalDevfiles';

export interface Props {
  agentPodStatus: AgentPodStatus | undefined;
  agentTerminalUrl: string | undefined;
  agentInstanceId: string | undefined;
  agentName: string | undefined;
  agentDescription: string | undefined;
  agentInitCommand: string | undefined;
  namespace: string;
  devfileName: string;
  devfileId: string;
  isDarkTheme: boolean;
  isTerminalExpanded: boolean;
  onStartAgent: () => Promise<void>;
  onStopAgent: () => void;
  onTerminalExpandToggle: () => void;
}

interface State {
  isStartingAgent: boolean;
  agentError: string | undefined;
}

export default class AgentPanel extends React.PureComponent<Props, State> {
  constructor(props: Props) {
    super(props);
    this.state = {
      isStartingAgent: false,
      agentError: undefined,
    };
  }

  private handleStartAgent = async () => {
    this.setState({ isStartingAgent: true, agentError: undefined });
    try {
      await this.props.onStartAgent();
    } catch (e) {
      const message = e instanceof Error ? e.message : 'Failed to start agent';
      this.setState({ agentError: message });
    } finally {
      this.setState({ isStartingAgent: false });
    }
  };

  private renderStartButton(): React.ReactElement {
    const { isStartingAgent } = this.state;
    return (
      <Button
        variant="primary"
        isLoading={isStartingAgent}
        isDisabled={isStartingAgent}
        onClick={this.handleStartAgent}
        data-testid="start-agent-button"
      >
        {isStartingAgent ? 'Starting...' : 'Start Agent'}
      </Button>
    );
  }

  private renderStopButton(): React.ReactElement {
    return (
      <Button
        variant="secondary"
        isDanger
        onClick={this.props.onStopAgent}
        data-testid="stop-agent-button"
      >
        Stop
      </Button>
    );
  }

  render(): React.ReactElement {
    const {
      agentPodStatus,
      agentTerminalUrl,
      agentInstanceId,
      agentName,
      agentDescription,
      agentInitCommand,
      namespace,
      devfileName,
      devfileId,
      isDarkTheme,
      isTerminalExpanded,
      onTerminalExpandToggle,
    } = this.props;
    const { agentError } = this.state;

    const agentDisplayId = agentInstanceId || agentPodStatus?.agentId;
    const tooltipContent = (
      <div>
        <div>
          <strong>{agentName || agentDisplayId}</strong>
        </div>
        {agentDescription && <div>{agentDescription}</div>}
      </div>
    );

    if (agentPodStatus) {
      const { phase } = agentPodStatus;
      const isRunning = phase === AgentPodPhase.RUNNING && agentPodStatus.ready;
      const isFailed =
        phase === AgentPodPhase.FAILED ||
        phase === AgentPodPhase.SUCCEEDED ||
        phase === AgentPodPhase.UNKNOWN;
      const isPending = phase === AgentPodPhase.PENDING;

      if (isRunning && agentTerminalUrl) {
        return (
          <div className={styles.terminalPanel} data-testid="agent-panel-terminal">
            <Flex
              alignItems={{ default: 'alignItemsCenter' }}
              gap={{ default: 'gapSm' }}
              className={styles.terminalToolbar}
            >
              <FlexItem>
                <Tooltip content={tooltipContent}>
                  <span className={styles.agentIdLabel}>Agent ID: {agentDisplayId}</span>
                </Tooltip>
              </FlexItem>
              <FlexItem align={{ default: 'alignRight' }}>
                <TerminalTools
                  isExpanded={isTerminalExpanded}
                  onToggleExpand={onTerminalExpandToggle}
                />
              </FlexItem>
            </Flex>
            <AgentTerminal
              terminalUrl={agentTerminalUrl}
              namespace={namespace}
              devfileName={devfileName}
              devfileId={devfileId}
              isDarkTheme={isDarkTheme}
              initCommand={agentInitCommand}
            />
            <Flex
              justifyContent={{ default: 'justifyContentFlexEnd' }}
              className={styles.terminalBottomToolbar}
            >
              <FlexItem>{this.renderStopButton()}</FlexItem>
            </Flex>
          </div>
        );
      }

      if (isFailed || isPending || phase === AgentPodPhase.RUNNING) {
        return (
          <div
            className={styles.terminalPanel}
            data-testid={isFailed ? 'agent-panel-failed' : 'agent-panel-pending'}
          >
            {isFailed && (
              <Alert variant="danger" isInline title="Agent failed" className={styles.failedAlert}>
                Agent pod status: {phase}
              </Alert>
            )}
            <Flex
              alignItems={{ default: 'alignItemsCenter' }}
              gap={{ default: 'gapSm' }}
              className={styles.terminalToolbar}
            >
              <FlexItem>
                <Tooltip content={tooltipContent}>
                  <span className={styles.agentIdLabel}>Agent ID: {agentDisplayId}</span>
                </Tooltip>
              </FlexItem>
              <FlexItem align={{ default: 'alignRight' }}>
                <TerminalTools
                  isExpanded={isTerminalExpanded}
                  onToggleExpand={onTerminalExpandToggle}
                />
              </FlexItem>
            </Flex>
            <AgentPodEvents podName={agentPodStatus.name} className={styles.podEvents} />
            <Flex
              justifyContent={{ default: 'justifyContentFlexEnd' }}
              className={styles.terminalBottomToolbar}
            >
              <FlexItem>{isFailed ? this.renderStartButton() : this.renderStopButton()}</FlexItem>
            </Flex>
          </div>
        );
      }
    }

    return (
      <Card isPlain className={styles.emptyPanel} data-testid="agent-panel-empty">
        <CardBody>
          {agentError && (
            <Alert variant="danger" isInline title="Agent error" className={styles.agentErrorAlert}>
              {agentError}
            </Alert>
          )}
          <EmptyState headingLevel="h3" titleText="AI Agent" variant={EmptyStateVariant.sm}>
            <EmptyStateBody>Start an AI agent to get help building your devfile.</EmptyStateBody>
            <EmptyStateFooter>
              <EmptyStateActions>{this.renderStartButton()}</EmptyStateActions>
            </EmptyStateFooter>
          </EmptyState>
        </CardBody>
      </Card>
    );
  }
}
